g.text:
          width: f64 @ 0x00
          row_height: f64 @ 0x08
          min_width: f64 @ 0x10
          font_size: u32 @ 0x18
          title: String @ 0x20
  }
  differential_analyzer: {
    shape: class
    label: "DifferentialAnalyzer\n[differential/compare.rs]"
  }
}
# M2 Connections
m2_layer.callgraph_builder -> m2_layer.callgraph_node: {
  label: "creates nodes\n48+ bytes each"
}
m2_layer.callgraph_builder -> m2_layer.collapsed_stack: {
  label: "converts to\ncollapsed format"
}
m2_layer.collapsed_stack -> m2_layer.flamegraph_renderer: {
  label: "stack data\nformat: a;b;c 42"
}
m2_layer.flamegraph_renderer -> m2_layer.flame_config: {
  label: "reads config"
}
m2_layer.differential_analyzer -> m2_layer.callgraph_builder: {
  label: "compares profiles\ndelta calculation"
}
m1_layer.raw_sample -> m2_layer.callgraph_builder: {
  label: "samples feed\nbuilder"
}
nav -> m2_layer: { label: "profiler-m2" }
# ============================================
# ROW 3: M3 - Memory Allocation Tracking
# ============================================
m3_layer: {
  label: "M3: Memory Allocation Tracking"
  memory_interpose: {
    shape: class
    label: "MemoryInterpose\n[memory/interpose.rs]"
  }
  allocation_info: {
    shape: sql_table
    label: "AllocationInfo [memory/tracker.rs]"
      fields:

          address: u64 @ 0x00
          size: usize @ 0x08
          age_ms: u64 @ 0x10
          call_stack: Vec_u64 @ 0x18
          classification: LeakClass @ 0x28
  }
  hotspot_analyzer: {
    shape: class
    label: "HotspotAnalyzer\n[memory/hotspot.rs]"
  }
}
# M3 Connections
m3_layer.memory_interpose -> m3_layer.memory_tracker: {
  label: "LD_PRELOAD hooks\nalloc/free events"
}
m3_layer.memory_tracker -> m3_layer.allocation_info: {
  label: "stores records\n264 bytes each"
}
m3_layer.memory_tracker -> m3_layer.leak_detector: {
  label: "queries live\nallocations"
}
m3_layer.leak_detector -> m3_layer.leak_report: {
  label: "generates\nleak reports"
}
m3_layer.memory_tracker -> m3_layer.hotspot_analyzer: {
  label: "aggregates\nallocation data"
}
nav -> m3_layer: { label: "profiler-m3" }
